class Solution(object):
    def modifiedMatrix(self, matrix):
        rows = len(matrix)
        cols = len(matrix[0])
        for c in range(cols):
            col_max = max(matrix[r][c] for r in range(rows) if matrix[r][c] != -1)
            for r in range(rows):
                if matrix[r][c] == -1:
                    matrix[r][c] = col_max
        return matrix
